```class Solution {
public:
    int findTheLongestSubstring(string s) {
        int n = s.size();
        int res = 0, cur = 0;
        vector<int> pos(5, -1);
        for (int i = 0; i < n; i++) {
            if (s[i] == 'a' || s[i] == 'e' || s[i] == 'i' || s[i] == 'o' || s[i] == 'u') {
                int idx = s[i] - 'a';
                if (pos[idx] != -1) cur -= 1 << idx;
                pos[idx] = i;
                cur += 1 << idx;
                res = max(res, i - pos[0]);
            }
        }
        return res;
    }
};```
